logic signed [25:0] inp_bb;
logic [25:0] tmp61;
// FIRRTL equivalent: tmp61 <= xor(SInt(0), inp_bb)
// SInt(0) has no explicit width; width inference must resolve it
assign tmp61 = $signed(inp_bb) ^ $signed(26'sh0);

logic [25:0] tmp61;
logic signed [25:0] inp_bb;
// Unsigned reg gets signed XOR: UInt<26> <= xor(SInt(0), SInt<26>)
always_ff @(posedge clock)
  tmp61 <= inp_bb ^ 26'sh0;

logic [25:0] tmp61;
// FIRRTL: reg tmp61: UInt<26>, clock with: (reset => (arst, UInt<26>(0)))
always_ff @(posedge clock or posedge arst)
  if (arst)
    tmp61 <= 26'd0;
  else
    tmp61 <= tmp61;

// FIRRTL: xor(SInt(0), inp_bb) where SInt(0) has no width
// SV analog: operand whose width must be inferred from context
logic signed [25:0] inp_bb;
logic signed [25:0] result;
assign result = inp_bb ^ $signed({26{1'b0}});
